function getJobTitle(job_id) {
  const jobs = getJobs();
  const job = jobs.find(j => String(j.job_id || j.id || "") === String(job_id));
  return job ? job.title : "Unknown";
}

function collectPlanFeatures(params, prefix) {
  return [
    params.get(`${prefix}_feature_negotiation`) ? "negotiation" : null,
    params.get(`${prefix}_feature_ai_workspace`) ? "ai_workspace" : null,
    params.get(`${prefix}_feature_copilot`) ? "copilot" : null,
    params.get(`${prefix}_feature_executive_export`) ? "executive_export" : null,
    params.get(`${prefix}_feature_payer_intelligence`) ? "payer_intelligence" : null,
    params.get(`${prefix}_feature_auto_drafts`) ? "auto_drafts" : null
  ].filter(Boolean);
}


function getActiveAnnouncements() {
  return readJSON(FILES.admin_announcements, [])
    .filter(a => a && a.status === "active");
}

function renderAnnouncementBanner(org_id, title, isAdmin=false) {
  if (isAdmin || title === "Login" || title === "Sign In") return "";

  const list = getActiveAnnouncements().filter(a => a.display === "banner");
  if (!list.length) return "";

  return `
    <div id="announcementTicker" style="
      background:#111827;
      color:#fff;
      overflow:hidden;
      white-space:nowrap;
      position:relative;
      padding:10px 0;
      font-weight:600;
    ">

      <div style="
        display:inline-block;
        padding-left:100%;
        animation:tickerScroll 20s linear infinite;
      ">
        ${list.map(a => `
          <span style="margin-right:40px;">
            <strong>${safeStr(a.title)}</strong> - ${safeStr(a.message)}
          </span>
        `).join("")}
      </div>

      <span onclick="
        document.getElementById('announcementTicker').remove();
        localStorage.setItem('hideAnnouncementBanner','1');
      "
      style="
        position:absolute;
        right:12px;
        top:6px;
        cursor:pointer;
        font-weight:900;
      ">✕</span>

    </div>

    <style>
      @keyframes tickerScroll {
        0% { transform: translateX(0%); }
        100% { transform: translateX(-100%); }
      }
    </style>

    <script>
      (function(){
        if(localStorage.getItem('hideAnnouncementBanner') === '1'){
          const el = document.getElementById('announcementTicker');
          if(el) el.remove();
        }
      })();
    </script>
  `;
}

function renderAnnouncementPopup(isAdmin=false, title="") {
  if (isAdmin || title === "Login" || title === "Sign In") return "";

  const list = getActiveAnnouncements().filter(a => a.display === "popup");
  if (!list.length) return "";

  const a = list[0];

  return `
    <div id="adminPopup" style="
      position:fixed;
      top:50%;
      left:50%;
      transform:translate(-50%,-50%);
      background:#fff;
      border:1px solid var(--border);
      border-radius:12px;
      padding:20px;
      z-index:9999;
      max-width:400px;
      box-shadow:0 20px 60px rgba(0,0,0,0.2);
    ">
      <h3>${safeStr(a.title)}</h3>
      <p>${safeStr(a.message)}</p>
      <button onclick="document.getElementById('adminPopup').remove(); localStorage.setItem('hideAdminPopup','1');" class="btn">Close</button>
    </div>
    <script>
      (function(){
        if(localStorage.getItem('hideAdminPopup') === '1'){
          const el = document.getElementById('adminPopup');
          if(el) el.remove();
        }
      })();
    </script>
  `;
}

// ===== Admin password =====
function adminHash() {
  if (ADMIN_PASSWORD_HASH) return ADMIN_PASSWORD_HASH;
  if (ADMIN_PASSWORD_PLAIN) return bcrypt.hashSync(ADMIN_PASSWORD_PLAIN, 10);
  return "";
}

