// EXECUTIVE ACTION ROUTING ENGINE
// ===============================
function buildActionUrl(base, params = {}) {
  const q = Object.entries(params)
    .filter(([_, v]) => v !== undefined && v !== null && String(v).trim() !== "")
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join("&");
  return q ? `${base}${base.includes("?") ? "&" : "?"}${q}` : base;
}

function determinePrimaryAction(result) {
  const briefType = String(result?.briefType || "EXECUTIVE_SNAPSHOT");
  const payerScope = String(result?.payerScope || "");
  const totals = result?.metrics?.totals || {};
  const rates = result?.metrics?.rates || {};

  const atRisk = Number(totals.atRisk || 0);
  const denialRate = Number(rates.denialRate || 0);

  if (briefType === "DENIAL_ANALYSIS" || denialRate >= 20) {
    return { type: "denials", label: payerScope ? "Review Payer Denials" : "Review Denials", priority: "high" };
  }
  if (briefType === "RISK_OVERVIEW" || atRisk >= 25000) {
    return { type: "underpayments", label: payerScope ? "Review Payer Underpayments" : "Review Underpayments", priority: "high" };
  }
  if (briefType === "AR_EXPOSURE") {
    return { type: "ar", label: "Review AR Aging", priority: "medium" };
  }
  if (briefType === "FORECAST_REPORT") {
    return { type: "forecast", label: "View Forecast", priority: "medium" };
  }
  if (briefType === "PAYER_PERFORMANCE" && payerScope) {
    return { type: "payerHub", label: "Open Payer Hub", priority: "medium" };
  }

  return { type: "overview", label: "Open Action Center", priority: "normal" };
}

function buildActionLinks(result, rangePreset = "last30") {
  const payerScope = String(result?.payerScope || "");
  const briefType = String(result?.briefType || "EXECUTIVE_SNAPSHOT");
  const links = [];

  links.push({
    type: "payerHub",
    label: "Open Payer Hub",
    url: buildActionUrl("/revenue-intelligence", { tab: "payers", payer: payerScope || "" })
  });

  links.push({
    type: "denials",
    label: payerScope ? "View Payer Denials" : "View Denials",
    url: buildActionUrl("/actions", { tab: "denials", payer: payerScope, range: rangePreset })
  });

  links.push({
    type: "underpayments",
    label: payerScope ? "View Payer Underpayments" : "View Underpayments",
    url: buildActionUrl("/actions", { tab: "underpayments", payer: payerScope, range: rangePreset })
  });

  links.push({
    type: "ar",
    label: "View AR / Aging",
    url: buildActionUrl("/revenue-intelligence", { tab: "executive", focus: "ar", payer: payerScope, range: rangePreset })
  });

  links.push({
    type: "forecast",
    label: "View Forecast",
    url: buildActionUrl("/revenue-intelligence", { tab: "forecast", payer: payerScope, range: rangePreset })
  });

  if (briefType === "PAYER_PERFORMANCE") return links.filter(x => ["payerHub", "denials", "underpayments"].includes(x.type));
  if (briefType === "DENIAL_ANALYSIS") return links.filter(x => ["denials", "payerHub"].includes(x.type));
  if (briefType === "AR_EXPOSURE") return links.filter(x => ["ar", "payerHub"].includes(x.type));
  if (briefType === "RISK_OVERVIEW") return links.filter(x => ["underpayments", "denials", "payerHub"].includes(x.type));
  if (briefType === "FORECAST_REPORT") return links.filter(x => ["forecast", "payerHub"].includes(x.type));

  return links.filter(x => ["payerHub", "denials", "underpayments"].includes(x.type));
}

function normalizePayerKey(v) {
  return String(v || "").trim().toLowerCase();
}

function canonicalizePayer(str) {
  return String(str || "")
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function tokenize(str) {
  return canonicalizePayer(str).split(" ").filter(Boolean);
}

// ===========================
// Levenshtein (typo tolerance)
// ===========================
function levenshtein(a, b) {
  a = String(a || "");
  b = String(b || "");
  if (a === b) return 0;
  const alen = a.length, blen = b.length;
  if (!alen) return blen;
  if (!blen) return alen;

  const v0 = new Array(blen + 1);
  const v1 = new Array(blen + 1);

  for (let i = 0; i <= blen; i++) v0[i] = i;

  for (let i = 0; i < alen; i++) {
    v1[0] = i + 1;
    for (let j = 0; j < blen; j++) {
      const cost = a[i] === b[j] ? 0 : 1;
      v1[j + 1] = Math.min(
        v1[j] + 1, // insertion
        v0[j + 1] + 1, // deletion
        v0[j] + cost // substitution
      );
    }
    for (let j = 0; j <= blen; j++) v0[j] = v1[j];
  }
  return v0[blen];
}

function typoSimilarity(a, b) {
  a = canonicalizePayer(a).replace(/\s+/g, "");
  b = canonicalizePayer(b).replace(/\s+/g, "");
  if (!a || !b) return 0;
  if (a === b) return 1;
  const dist = levenshtein(a, b);
  const maxLen = Math.max(a.length, b.length);
  const score = 1 - (dist / maxLen);
  return Math.max(0, Math.min(1, score));
}

function payerAcronym(str) {
  const parts = tokenize(str);
  if (!parts.length) return "";
  return parts.map(t => t[0]).join("");
}

function simpleSimilarity(a, b) {
  if (!a || !b) return 0;

  if (a === b) return 1;

  if (a.includes(b) || b.includes(a)) return 0.8;

  const tokensA = tokenize(a);
  const tokensB = tokenize(b);
  const acronymA = payerAcronym(a);
  const acronymB = payerAcronym(b);

  if (acronymA && acronymB && acronymA === acronymB) return 0.95;
  if ((acronymA && acronymA === b.replace(/\s+/g, "")) || (acronymB && acronymB === a.replace(/\s+/g, ""))) return 0.9;

  const overlap = tokensA.filter(t => tokensB.includes(t)).length;
  const tokenScore = overlap / Math.max(tokensA.length, tokensB.length);

  const prefixOverlap = tokensA.filter(t => tokensB.some(x => x.startsWith(t) || t.startsWith(x))).length;
  const prefixScore = prefixOverlap / Math.max(tokensA.length, tokensB.length);

  // NEW: typo tolerance helps single-word misspellings like "humanna" -> "humana"
  const typoScore = typoSimilarity(a, b);

  return Math.max(tokenScore, prefixScore * 0.9, typoScore * 0.95);
}

function getOrgPayerNames(org_id) {
  const names = new Set();
  const billed = readJSON(FILES.billed, []).filter(b => b.org_id === org_id);
  const payments = readJSON(FILES.payments, []).filter(p => p.org_id === org_id);

  billed.forEach(b => {
    const payer = String((b.payer || "").trim());
    if (payer) names.add(payer);
  });

  payments.forEach(p => {
    const payer = String((p.payer || "").trim());
    if (payer) names.add(payer);
  });

  return Array.from(names);
}

function findPayerCandidates(org_id, payerQuery) {
  const all = getOrgPayerNames(org_id);
  const query = canonicalizePayer(payerQuery);
  if (!query) return [];

  const scored = [];

  for (const name of all) {
    const canonName = canonicalizePayer(name);

    let score = 0;

    // exact canonical match
    if (canonName === query) {
      score = 1;
    } else {
      score = simpleSimilarity(canonName, query);
    }

    if (score > 0.35) {
      scored.push({ name, score });
    }
  }

  return scored
    .sort((a, b) => b.score - a.score)
    .map(x => x.name);
}

function detectPayerFromPrompt(prompt, org_id) {
  const text = String(prompt || "").trim();
  if (!text) return "";

  const candidates = detectPayerCandidatesFromPrompt(text, org_id);

  if (!candidates.length) return "";

  // Score each candidate against the extracted phrase
  const scored = candidates.map(name => ({
    name,
    score: simpleSimilarity(
      canonicalizePayer(name),
      canonicalizePayer(text)
    )
  })).sort((a, b) => b.score - a.score);

  const best = scored[0];

  // 🔥 Strong match rule
  if (best.score >= 0.65) {
    return best.name;
  }

  // 🔥 Dominant match rule
  if (scored.length > 1 && (best.score - scored[1].score) >= 0.25) {
    return best.name;
  }

  // Otherwise ambiguous
  return "";
}

function detectPayerCandidatesFromPrompt(prompt, org_id) {
  const text = String(prompt || "").trim();
  if (!text) return [];

  const patterns = [
    /how much did\s+(.+?)\s+pay/i,
    /total paid by\s+(.+)/i,
    /what did\s+(.+?)\s+collect/i,
    /denial rate\s+(?:for|of)\s+(.+)/i,
    /at risk\s+(?:for|of)\s+(.+)/i,
    /claims\s+(?:for|from|by)\s+(.+)/i,
    /how is\s+(.+?)\s+doing/i,
    /performance\s+(?:for|of)\s+(.+)/i,
    /overview\s+(?:for|of)\s+(.+)/i,
    /metrics\s+(?:for|of)\s+(.+)/i
  ];

  for (const re of patterns) {
    const m = text.match(re);
    if (m && m[1]) {
      const extracted = String(m[1] || "").replace(/[?.!,]+$/g, "").trim();
      const candidates = findPayerCandidates(org_id, extracted);
      if (candidates.length) return candidates;
    }
  }

  return findPayerCandidates(org_id, text);
}

function computePayerSpecificMetrics(org_id, payerScope, rangePreset = "last30") {
  const intel = computePayerIntelligence(org_id, payerScope, rangePreset);
  return {
    payerScope: payerScope,
    topPayers: [{ payer: payerScope, risk: round2(intel.totalAtRisk || 0) }],
    metrics: {
      totals: {
        billed: round2(intel.totalBilled || 0),
        collected: round2(intel.totalCollected || 0),
        expected: round2(intel.totalBilled || 0),
        atRisk: round2(intel.totalAtRisk || 0)
      },
      rates: {
        recoveryRate: round2(intel.recoveryRate || 0),
        denialRate: round2(intel.denialRate || 0),
        appealSuccessRate: round2(intel.recoveryRate || 0),
        negotiationROI: 0
      },
      disciplineScore: round2(intel.score || 0)
    },
    forecast: {
      currentAtRisk: round2(intel.totalAtRisk || 0),
      slopePerDay: 0,
      projected30: round2(intel.totalAtRisk || 0),
      projected60: round2(intel.totalAtRisk || 0),
      projected90: round2(intel.totalAtRisk || 0)
    },
    denialForecast: {
      currentRate: round2(intel.denialRate || 0),
      projected30: round2(intel.denialRate || 0),
      projected60: round2(intel.denialRate || 0),
      projected90: round2(intel.denialRate || 0),
      velocity: "Stable"
    }
  };
}

function aggregatePayerPayments(org_id, payerNames, days = null) {
  const payerKeys = new Set((Array.isArray(payerNames) ? payerNames : [payerNames]).map(normalizePayerKey));
  const cutoff = Number.isFinite(days) && days > 0 ? (Date.now() - days * 24 * 60 * 60 * 1000) : null;
  const payments = readJSON(FILES.payments, []).filter(p => {
    if (p.org_id !== org_id) return false;
    if (!payerKeys.has(normalizePayerKey(p.payer))) return false;
    if (!cutoff) return true;
    const when = new Date(p.date_paid || p.created_at || nowISO()).getTime();
    return Number.isFinite(when) && when >= cutoff;
  });

  return {
    totalPaid: round2(payments.reduce((sum, p) => sum + num(p.amount_paid), 0)),
    totalClaims: payments.length
  };
}

function tryHandleUIQuestion(message, currentPath = "") {
  const text = String(message || "").toLowerCase();

  if (/what does this tab do/i.test(text)) {
    if (currentPath.includes("/revenue-intelligence")) {
      return "The Revenue Intelligence tab provides executive summaries, payer analysis, forecasts, and performance metrics to help you identify revenue risks and optimization opportunities.";
    }
    if (currentPath.includes("/data-management")) {
      return "The Data Management tab allows you to manage claims, payments, denials, reimbursement logic, and automation templates.";
    }
    if (currentPath.includes("/ai-copilot")) {
      return "The AI Copilot allows you to ask questions about your revenue data and generate executive briefs.";
    }
    return "This tab provides revenue management functionality within TJ Healthcare Pro.";
  }

  return null;
}

function tryBuildDeterministicPayerAnswer(org_id, message) {
  const text = String(message || "").trim();
  const isDenialQ = /denial rate/i.test(text);
  const isAtRiskQ = /at risk/i.test(text);
  const isClaimsQ = /how many claims/i.test(text) || /\bclaims\b/i.test(text);
  const isCollectedQ = /collected/i.test(text) || /total collected/i.test(text);
  const isPerformanceQ =
    /how is/i.test(text) ||
    /performance/i.test(text) ||
    /overview/i.test(text) ||
    /metrics/i.test(text) ||
    /doing/i.test(text);

  const patterns = [
    /how much did\s+(.+?)\s+pay/i,
    /total paid by\s+(.+)/i,
    /what did\s+(.+?)\s+collect/i,
    /denial rate\s+(?:for|of)\s+(.+)/i,
    /at risk\s+(?:for|of)\s+(.+)/i,
    /how many claims\s+(?:for|from|by)\s+(.+)/i,
    /claims\s+(?:for|from|by)\s+(.+)/i,
    /(?:total\s+)?collected\s+(?:for|from|by)\s+(.+)/i,
    /how is\s+(.+?)\s+doing/i,
    /performance\s+(?:for|of)\s+(.+)/i,
    /overview\s+(?:for|of)\s+(.+)/i,
    /metrics\s+(?:for|of)\s+(.+)/i
  ];

  let extracted = "";
  for (const re of patterns) {
    const m = text.match(re);
    if (m && m[1]) {
      extracted = String(m[1] || "").replace(/[?.!,]+$/g, "").trim();
      break;
    }
  }

  if (!extracted) return null;

  const candidates = findPayerCandidates(org_id, extracted);
  const exact = candidates.find(c => canonicalizePayer(c) === canonicalizePayer(extracted));
  const payerScope = exact || (candidates.length === 1 ? candidates[0] : "");

  if (payerScope) {
    const intel = computePayerIntelligence(org_id, payerScope, "last30");

    if (isPerformanceQ) {
      return {
        deterministic: true,
        answer:
          `${payerScope} Performance (last 30 days):\n` +
          `Total Paid: ${formatMoneyUI(intel.totalCollected || 0)}\n` +
          `Claims: ${Math.round(intel.totalClaims || 0)}\n` +
          `Denial Rate: ${Math.round(intel.denialRate || 0)}%\n` +
          `At Risk: ${formatMoneyUI(intel.totalAtRisk || 0)}\n` +
          `Avg Days to Pay: ${Math.round(intel.avgDaysToPay || 0)}`
      };
    }

    if (isDenialQ) {
      return { answer: `${payerScope} denial rate is ${Math.round(intel.denialRate || 0)}% (last 30 days). Claims: ${Math.round(intel.totalClaims || 0)}.`, deterministic: true };
    }
    if (isAtRiskQ) {
      return { answer: `${payerScope} has ${formatMoneyUI(intel.totalAtRisk || 0)} at risk (last 30 days).`, deterministic: true };
    }
    if (isClaimsQ) {
      return { answer: `${payerScope} has ${Math.round(intel.totalClaims || 0)} claims (last 30 days).`, deterministic: true };
    }
    if (isCollectedQ) {
      return { answer: `${payerScope} collected ${formatMoneyUI(intel.totalCollected || 0)} (last 30 days).`, deterministic: true };
    }

    return {
      deterministic: true,
      answer: `${payerScope} has paid ${formatMoneyUI(intel.totalCollected || 0)} across ${Math.round(intel.totalClaims || 0)} claims.\nDenial rate: ${Math.round(intel.denialRate || 0)}%\nAt risk: ${formatMoneyUI(intel.totalAtRisk || 0)}\nAverage days to pay: ${Math.round(intel.avgDaysToPay || 0)}`,
      payerScope,
      totalCollected: round2(intel.totalCollected || 0),
      totalClaims: Math.round(intel.totalClaims || 0),
      totalAtRisk: round2(intel.totalAtRisk || 0),
      denialRate: round2(intel.denialRate || 0)
    };
  }

  if (!payerScope && candidates.length > 0) {
    return {
      deterministic: true,
      ambiguous: true,
      answer:
        `I found multiple possible matches for "${extracted}":\n` +
        candidates.map(c => `- ${c}`).join("\n") +
        `\n\nPlease reply with the exact payer name.`
    };
  }

  return null;
}

function computeSimpleAtRiskForecast(org_id, rangePreset){
  const r = rangeFromPreset(rangePreset || "last30");

  // compare first half vs second half of the range
  const mid = new Date((r.start.getTime() + r.end.getTime()) / 2);

  const m1 = computeDashboardMetrics(org_id, r.start, mid, r.preset);
  const m2 = computeDashboardMetrics(org_id, mid, r.end, r.preset);

  const a1 = Number(m1?.kpis?.revenueAtRisk || 0);
  const a2 = Number(m2?.kpis?.revenueAtRisk || 0);
  const safeA1 = Number.isFinite(a1) ? a1 : 0;
  const safeA2 = Number.isFinite(a2) ? a2 : 0;

  // daily slope estimate across half-range
  const days = Math.max(1, (r.end.getTime() - r.start.getTime()) / (1000 * 60 * 60 * 24));
  const slopePerDay = (safeA2 - safeA1) / (days / 2);
  const safeSlopePerDay = Number.isFinite(slopePerDay) ? slopePerDay : 0;

  // project 30/60/90 days out
  const projected30 = Math.max(0, safeA2 + (safeSlopePerDay * 30));
  const projected60 = Math.max(0, safeA2 + (safeSlopePerDay * 60));
  const projected90 = Math.max(0, safeA2 + (safeSlopePerDay * 90));

  return {
    currentAtRisk: safeA2,
    slopePerDay: safeSlopePerDay,
    projected30: Number.isFinite(projected30) ? projected30 : 0,
    projected60: Number.isFinite(projected60) ? projected60 : 0,
    projected90: Number.isFinite(projected90) ? projected90 : 0
  };
}

function computeSimpleDenialRateForecast(org_id, rangePreset){
  const r = rangeFromPreset(rangePreset || "last30");
  const mid = new Date((r.start.getTime() + r.end.getTime()) / 2);

  const m1 = computeDashboardMetrics(org_id, r.start, mid, r.preset);
  const m2 = computeDashboardMetrics(org_id, mid, r.end, r.preset);

  const d1 = Number(m1?.denialRate || 0);
  const d2 = Number(m2?.denialRate || 0);

  const safeD1 = Number.isFinite(d1) ? d1 : 0;
  const safeD2 = Number.isFinite(d2) ? d2 : 0;

  const days = Math.max(1, (r.end.getTime() - r.start.getTime()) / (1000*60*60*24));
  const slopePerDay = (safeD2 - safeD1) / (days / 2);
  const safeSlopePerDay = Number.isFinite(slopePerDay) ? slopePerDay : 0;

  const proj30 = safeD2 + (safeSlopePerDay * 30);
  const proj60 = safeD2 + (safeSlopePerDay * 60);
  const proj90 = safeD2 + (safeSlopePerDay * 90);

  const clamp = (x)=> Math.max(0, Math.min(100, Number.isFinite(x) ? x : 0));

  const velocity =
    (safeD2 > 15) ? "High" :
    (safeD2 > 8)  ? "Moderate" :
    "Stable";

  return {
    currentDenialRate: clamp(safeD2),
    slopePerDay: safeSlopePerDay,
    projected30: clamp(proj30),
    projected60: clamp(proj60),
    projected90: clamp(proj90),
    velocity
  };
}

function renderCopilotTiles(){
  const tiles = [
    { title:"Executive Revenue Snapshot", subtitle:"High-level performance overview", prompt:"Executive revenue snapshot for the last 30 days. Include billed, collected, revenue at risk, denial rate, recovery rate, and top risk payer." },
    { title:"Revenue Risk Drivers", subtitle:"What is increasing exposure", prompt:"What are the top revenue risk drivers right now? Break down denials, underpayments, and AR aging. Provide top 5 actions to reduce exposure." },
    { title:"Payer Exposure Overview", subtitle:"Risk concentration by payer", prompt:"Analyze payer exposure. Which payers drive the most at-risk dollars, denial rate, and underpayments? Provide a ranked list and suggested actions." },
    { title:"Denial Performance", subtitle:"Denial trends and appeal health", prompt:"Review denial performance: denial rate trend, top denial reasons, top denial payers, and recommended appeal focus areas." },
    { title:"Underpayment Recovery", subtitle:"Negotiation effectiveness", prompt:"Evaluate underpayment recovery: negotiation ROI, underpaid dollars, top underpaying payers, and tactics to improve recovery." },
    { title:"Operational Health", subtitle:"Readiness + workflow posture", prompt:"Provide an operational health summary: AI Case Readiness, documentation gaps, and process improvements to speed appeal/negotiation cycles." }
  ];

  const tilesB64 = Buffer.from(JSON.stringify(tiles)).toString("base64");

  return `
  <div class="tile-grid" id="copilotTileGrid" data-tiles="${tilesB64}">
    ${tiles.map((t,i)=>`
      <button type="button" class="tile" data-i="${i}">
        <div class="tile-title">${safeStr(t.title)}</div>
        <div class="tile-sub">${safeStr(t.subtitle)}</div>
      </button>
    `).join("")}
  </div>
  `;
}
