function buildCopilotResponse({
  org_id,
  rangePreset,
  responseFormat,
  question
}){

  const range = rangeFromPreset(rangePreset || "last30");
  const payerScope = detectPayerFromPrompt(question, org_id);
  const intent = detectCopilotIntent(question);
  const briefType = determineBriefType({ question, intentKey: intent.key, payerScope });
  const briefTitle = buildBriefTitle({ briefType, payerScope, question });
  let dashboard = null;
  let metrics = null;
  let topPayers = [];
  let scoped = null;

  if (payerScope) {
    scoped = computePayerSpecificMetrics(org_id, payerScope, rangePreset);
    metrics = scoped.metrics;
    topPayers = scoped.topPayers;
  } else {
    dashboard = computeDashboardMetrics(org_id, range.start, range.end, range.preset);
    metrics = {
      totals: {
        billed: round2(dashboard?.kpis?.totalBilled || 0),
        collected: round2(dashboard?.kpis?.collectedTotal || 0),
        expected: round2(dashboard?.kpis?.allowedTotal || dashboard?.kpis?.totalBilled || 0),
        atRisk: round2(dashboard?.kpis?.revenueAtRisk || 0)
      },
      rates: {
        recoveryRate: round2(
          dashboard?.kpis?.netCollectionRate ??
          dashboard?.kpis?.grossCollectionRate ??
          0
        ),
        denialRate: round2(dashboard?.denialRate ?? 0),
        appealSuccessRate: round2(dashboard?.appealSuccessRate ?? 0),
        negotiationROI: round2(dashboard?.negotiationROI ?? 0)
      },
      disciplineScore: round2(
        dashboard?.operationalDisciplineScore ?? 0
      )
    };
    topPayers = Array.isArray(dashboard?.payerRiskRanking)
      ? dashboard.payerRiskRanking
      : [];
  }
  const forecast = scoped ? scoped.forecast : computeSimpleAtRiskForecast(org_id, rangePreset);
  const denialForecast = scoped ? scoped.denialForecast : computeSimpleDenialRateForecast(org_id, rangePreset);
  const format = String(responseFormat || "executive").toLowerCase();
  const disciplineBreakdown = [
    { label: "Denial Rate", value: metrics.rates.denialRate },
    { label: "Recovery Rate", value: metrics.rates.recoveryRate },
    { label: "Appeal Success", value: metrics.rates.appealSuccessRate },
    { label: "Negotiation ROI", value: metrics.rates.negotiationROI }
  ];

  const disciplineDrivers = [];

  if (metrics.rates.denialRate > 15) {
    disciplineDrivers.push("Denial rate exceeds 15% threshold.");
  }

  if (metrics.rates.recoveryRate < 80) {
    disciplineDrivers.push("Recovery rate below 80% target.");
  }

  if (metrics.rates.appealSuccessRate < 50) {
    disciplineDrivers.push("Appeal success rate under 50%.");
  }

  if (metrics.rates.negotiationROI < 50) {
    disciplineDrivers.push("Negotiation ROI below 50%.");
  }

  if (metrics.totals.atRisk > metrics.totals.billed * 0.2) {
    disciplineDrivers.push("Revenue at risk exceeds 20% of billed.");
  }

  const executiveActions = [];

  if (metrics.totals.atRisk > 0) {
    executiveActions.push("Prioritize highest at-risk claims in Action Center.");
  }

  if (metrics.rates.denialRate > 15) {
    executiveActions.push("Review top denial payer performance.");
  }

  if (metrics.rates.negotiationROI < 50) {
    executiveActions.push("Escalate negotiation review process.");
  }

  if (metrics.rates.appealSuccessRate < 50) {
    executiveActions.push("Audit appeal documentation quality.");
  }

  let bullets = [];

  if (format === "executive"){
    bullets = [
      `Total Revenue Billed: $${metrics.totals.billed.toLocaleString()}`,
      `Total Revenue Collected: $${metrics.totals.collected.toLocaleString()}`,
      `Revenue At Risk: $${metrics.totals.atRisk.toLocaleString()}`,
      `Recovery Rate: ${metrics.rates.recoveryRate}%`,
      `Denial Rate: ${metrics.rates.denialRate}%`,
      `AI Case Readiness Score: ${metrics.disciplineScore}/100`,
      `30-day At-Risk Projection: $${Math.round(forecast.projected30).toLocaleString()} (trend: ${Math.round(forecast.slopePerDay).toLocaleString()}/day)`
    ];

    bullets.push(
      `60/90-day At-Risk Projection: $${Math.round(forecast.projected60).toLocaleString()} / $${Math.round(forecast.projected90).toLocaleString()}`
    );

    bullets.push(
      `Denial Rate Forecast (30/60/90): ${denialForecast.projected30.toFixed(1)}% / ${denialForecast.projected60.toFixed(1)}% / ${denialForecast.projected90.toFixed(1)}% (velocity: ${denialForecast.velocity})`
    );

    if (topPayers.length > 0) {
      bullets.push(`Top Risk Payer: ${topPayers[0].payer} ($${Math.round(topPayers[0].risk).toLocaleString()} at risk)`);
    }
  }

  else if (format === "operational"){
    bullets = [
      `Appeal Success Rate: ${metrics.rates.appealSuccessRate}%`,
      `Negotiation ROI: ${metrics.rates.negotiationROI}%`,
      `Revenue Exposure: $${metrics.totals.atRisk.toLocaleString()}`,
      `AI Case Readiness Composite: ${metrics.disciplineScore}`
    ];
  }

  else if (format === "deep"){
    bullets = [
      `Expected vs Collected Gap: $${(metrics.totals.expected - metrics.totals.collected).toLocaleString()}`,
      `Denial Exposure Rate: ${metrics.rates.denialRate}%`,
      `Appeal Conversion: ${metrics.rates.appealSuccessRate}%`,
      `Negotiation Yield: ${metrics.rates.negotiationROI}%`,
      `Discipline Score: ${metrics.disciplineScore}`,
      `30-day At-Risk Projection: $${Math.round(forecast.projected30).toLocaleString()} (trend: ${Math.round(forecast.slopePerDay).toLocaleString()}/day)`
    ];
  }

  else {
    bullets = [
      `Revenue At Risk: $${metrics.totals.atRisk.toLocaleString()}`,
      `Recovery Rate: ${metrics.rates.recoveryRate}%`,
      `Discipline Score: ${metrics.disciplineScore}`
    ];
  }

  const charts = [
    {
      title: "Revenue Overview",
      type: "bar",
      labels: ["Billed", "Collected", "At Risk"],
      datasets: [{
        label: "Revenue",
        data: [
          metrics.totals.billed,
          metrics.totals.collected,
          metrics.totals.atRisk
        ]
      }]
    },
    {
      title: "Performance Rates",
      type: "bar",
      labels: ["Recovery", "Denial", "Appeal Success", "Negotiation ROI"],
      datasets: [{
        label: "Rates (%)",
        data: [
          metrics.rates.recoveryRate,
          metrics.rates.denialRate,
          metrics.rates.appealSuccessRate,
          metrics.rates.negotiationROI
        ]
      }]
    }
  ];

  const payerRiskScore = round2(
    (metrics.rates.denialRate * 0.4) +
    (metrics.rates.negotiationROI < 50 ? 20 : 0) +
    (metrics.totals.atRisk > metrics.totals.billed * 0.2 ? 20 : 0)
  );

  const primaryAction = determinePrimaryAction({ briefType, payerScope, metrics, forecast, denialForecast });
  const actionLinks = buildActionLinks({ briefType, payerScope, metrics }, rangePreset || "last30");

  return {
    briefType,
    briefTitle,
    intentKey: intent.key,
    bullets,
    charts,
    metrics,
    payerScope,
    forecast,
    denialForecast,
    disciplineBreakdown,
    disciplineDrivers,
    executiveActions,
    payerRiskScore,
    topPayers,
    primaryAction,
    actionLinks
  };
}


