const PLAN_RUNTIME_DEFAULTS = {
  starter: { ai_chat_limit: 50, copilot_limit: 50, workspace_limit: 20, case_credits_per_month: 50, payment_tracking_credits_per_month: 10 },
  growth: { ai_chat_limit: 150, copilot_limit: 150, workspace_limit: 75, case_credits_per_month: 150, payment_tracking_credits_per_month: 50 },
  pro: { ai_chat_limit: 400, copilot_limit: 400, workspace_limit: 200, case_credits_per_month: 400, payment_tracking_credits_per_month: 150 },
  enterprise: { ai_chat_limit: 999999, copilot_limit: 999999, workspace_limit: 999999, case_credits_per_month: 999999, payment_tracking_credits_per_month: 999999 },
};

if (!PLAN_RUNTIME_DEFAULTS.pro) {
  console.error("PLAN_RUNTIME_DEFAULTS not defined before Copilot module.");
}
Object.keys(PLAN_RUNTIME_DEFAULTS).forEach(plan => {
  if (!PLAN_RUNTIME_DEFAULTS[plan].copilot_limit) {
    PLAN_RUNTIME_DEFAULTS[plan].copilot_limit = 50;
  }
  if (!PLAN_RUNTIME_DEFAULTS[plan].workspace_limit) {
    PLAN_RUNTIME_DEFAULTS[plan].workspace_limit = 50;
  }
});

function getPlanConfig(plan) {
  const defaults = {
    starter: { ai_generations: 20, claims_limit: 50, payment_limits: 10, features: ["basic"] },
    growth: { ai_generations: 100, claims_limit: 250, payment_limits: 50, features: ["negotiation"] },
    pro: {
      ai_generations: 500,
      claims_limit: 1000,
      payment_limits: 150,
      features: [
        "negotiation",
        "ai_workspace",
        "copilot",
        "executive_export",
        "payer_intelligence",
        "auto_drafts"
      ]
    },
    enterprise: { ai_generations: 999999, claims_limit: 999999, payment_limits: 999999, features: ["all"] }
  };

  const key = String(plan || "starter").toLowerCase();
  const saved = getPlanSettings();
  const merged = {
    ...defaults.starter,
    ...(defaults[key] || {}),
    ...(saved[key] || {})
  };
  const fallbackFeatures = Array.isArray((defaults[key] || {}).features) ? (defaults[key] || {}).features : defaults.starter.features;
  merged.features = Array.isArray(saved[key]?.features) ? saved[key].features : fallbackFeatures;
  return merged;
}

function checkUsageLimits(org_id) {
  const usage = getUsage(org_id);
  const sub = getSub(org_id);
  const plan = String((sub && sub.plan) || "starter").toLowerCase();
  const config = getPlanConfig(plan);
  const aiUsed = Number(usage?.monthly_ai_generations_used || 0);
  const claimsUsed = Number(usage?.claims_processed || usage?.monthly_case_credits_used || 0);

  return {
    aiExceeded: aiUsed >= config.ai_generations,
    claimsExceeded: claimsUsed >= config.claims_limit,
    plan,
    config,
    usage
  };
}

