function scoreCollectionRate(rate){
  if (rate >= 85) return 100;
  if (rate >= 75) return 85;
  if (rate >= 65) return 70;
  if (rate >= 55) return 55;
  return 40;
}

function scoreDenialRate(rate){
  if (rate <= 5) return 100;
  if (rate <= 10) return 85;
  if (rate <= 15) return 70;
  if (rate <= 20) return 55;
  return 40;
}

function scoreUnderpaidRate(rate){
  if (rate <= 5) return 100;
  if (rate <= 10) return 85;
  if (rate <= 15) return 70;
  if (rate <= 20) return 55;
  return 40;
}

function scoreDaysToPay(days){
  if (days <= 20) return 100;
  if (days <= 30) return 85;
  if (days <= 45) return 70;
  if (days <= 60) return 55;
  return 40;
}

function scoreARAging(rate){
  if (rate <= 10) return 100;
  if (rate <= 20) return 85;
  if (rate <= 30) return 70;
  if (rate <= 40) return 55;
  return 40;
}

function scoreOperationalDiscipline(rate){
  // rate = % of AI workspaces with required docs present (by channel) among "ready/submitted/closed"
  if (rate >= 90) return 100;
  if (rate >= 75) return 85;
  if (rate >= 60) return 70;
  if (rate >= 40) return 55;
  return 40;
}

function clampPct(n){
  const v = Number(n || 0);
  if (!isFinite(v)) return 0;
  return Math.max(0, Math.min(100, v));
}

function gradeFromScore(score){
  if (score >= 90) return "A";
  if (score >= 80) return "B";
  if (score >= 70) return "C";
  if (score >= 60) return "D";
  return "F";
}

function findContractForClaim(org_id, b){

  const claim = stampCanonicalClaimFields({ ...b });
  const contracts = getPayerContracts(org_id).map(normalizeContract);

  // 🔥 DEBUG ONLY FOR PROBLEM CLAIM
  debugClaimAndContracts(org_id, claim, contracts);

  let best = null;

  for (const c of contracts){
    if (!contractMatchesClaim(c, claim)) continue;

    best = c;
    break; // first match wins (for now)
  }

  return best || null;
}
function contractExpectedAmount(contract, billedAmount){
  if (!contract) return null;
  const model = String(contract.reimbursement_model || "fixed_amount");
  const value = num(contract.expected_value);
  const billed = num(billedAmount);
  if (model === "percent_of_charge") return billed * (value / 100);
  if (model === "percent_of_medicare") return billed * (value / 100);
  return value;
}

function classifyClaimStatusWithContract(claim){
  const d = evaluateClaimDerived(claim, {});
  return String(d.lifecycleStage || claim.status || "Waiting Payment");
}

function recalculateContractsForOrg(org_id){
  const billedAll = readJSON(FILES.billed, []);
  let changed = false;
  for (const b of billedAll) {
    if (b.org_id !== org_id) continue;
    stampCanonicalClaimFields(b);
    const contracts = getPayerContracts(org_id).map(normalizeContract);
    const contract = findContractForClaim(org_id, b);

    debugLog("Claim processed:", {
      claim: b.claim_number,
      payer: b.payer,
      claim_payer_raw: b.claim_payer_raw,
      claim_procedure_code_raw: b.claim_procedure_code_raw,
      claim_diagnosis_code_raw: b.claim_diagnosis_code_raw,
      rawProcedure: b.procedure_code,
      rawCpt: b.cpt_code,
      rawCode: b.code,
      rawHcpcs: b.hcpcs,
      rawServiceCode: b.service_code,
      rawBillingCode: b.billing_code,
      rawPrimaryProcedure: b.primary_procedure,
      rawDx: b.diagnosis_code,
      rawIcd10: b.icd10,
      rawIcd10Code: b.icd10_code,
      rawDxCode: b.dx_code,
      canonicalPayer: b.claim_payer_normalized,
      canonicalCpt: b.claim_procedure_code_normalized,
      canonicalDx: b.claim_diagnosis_code_normalized,
      finalCpt: getClaimProcedureCode(b),
      finalDx: getClaimDiagnosisCode(b),
      matchedContract: contract?.contract_id || null
    });
    debugLog("Contract candidates evaluated:", {
      claim_number: b?.claim_number,
      count: contracts.length
    });

    if (!contract) {
      b.expected_insurance = "";
      b.underpaid_amount = 0;
      b.network_status = "Unknown";
      b.contract_applied = false;
      b.contract_rule_id = "";
      b.contract_expected_amount = 0;
      b.contract_expected_value = 0;
      b.contract_reimbursement_model = "";
      changed = true;
      continue;
    }

    const billedAmt = num(b.amount_billed);
    const expectedAmount = num(contractExpectedAmount(contract, billedAmt));
    const expectedInsurance = Math.max(0, expectedAmount - num(b.patient_responsibility));

    const paid = num(b.insurance_paid || b.paid_amount);
    const underpaid = Math.max(0, expectedInsurance - paid);

    b.network_status = String(contract.network_status || "Unknown");
    b.contract_applied = true;
    b.contract_rule_id = String(contract.contract_id || "");
    b.contract_reimbursement_model = contract.reimbursement_model;
    b.contract_expected_value = num(contract.expected_value);
    b.contract_expected_amount = expectedAmount;
    b.expected_insurance = expectedInsurance;
    b.underpaid_amount = underpaid;
    b.status = classifyClaimStatusWithContract(b);
    changed = true;
  }
  if (changed) {
    writeJSON(FILES.billed, billedAll);
  }
}

function backfillCanonicalClaimFieldsForOrg(org_id){
  const billedAll = readJSON(FILES.billed, []);
  let changed = false;

  for (const b of billedAll) {
    if (b.org_id !== org_id) continue;

    const beforePayer = b.claim_payer_normalized || "";
    const beforeProc = b.claim_procedure_code_normalized || "";
    const beforeDx = b.claim_diagnosis_code_normalized || "";

    stampCanonicalClaimFields(b);

    if (
      beforePayer !== (b.claim_payer_normalized || "") ||
      beforeProc !== (b.claim_procedure_code_normalized || "") ||
      beforeDx !== (b.claim_diagnosis_code_normalized || "")
    ) {
      changed = true;
    }
  }

  if (changed) writeJSON(FILES.billed, billedAll);
}

function getClaimBatchHistory(org_id){
  return readJSON(FILES.upload_batches, [])
    .filter(b => b.org_id === org_id)
    .map(b => ({
      upload_id: String(b.upload_id || ""),
      filename: b.file_name || "batch",
      uploaded_at: b.uploaded_at,
      uploaded_by: b.uploaded_by || "",
      claim_count: num(b.claim_count),
      total_billed: num(b.total_billed),
    }))
    .sort((a, b) => new Date(b.uploaded_at || 0).getTime() - new Date(a.uploaded_at || 0).getTime());
}

function getPaymentBatchHistory(org_id){
  const payments = readJSON(FILES.payments, []).filter(p => p.org_id === org_id);
  const map = {};
  for (const p of payments) {
    const source = String(p.source_file || "manual").trim() || "manual";
    if (!map[source]) map[source] = { source_file: source, row_count: 0, total_paid: 0, uploaded_at: p.created_at || p.date_paid || nowISO() };
    map[source].row_count += 1;
    map[source].total_paid += num(p.amount_paid);
    const dt = new Date(p.created_at || p.date_paid || 0).getTime();
    if (dt > new Date(map[source].uploaded_at || 0).getTime()) map[source].uploaded_at = p.created_at || p.date_paid || map[source].uploaded_at;
  }
  return Object.values(map).sort((a, b) => new Date(b.uploaded_at || 0).getTime() - new Date(a.uploaded_at || 0).getTime());
}

function getUnmatchedPayments(org_id, billed){
  const payments = readJSON(FILES.payments, []).filter(p => p.org_id === org_id);
  return payments.filter(p => !findBilledByClaim(org_id, billed, p.claim_number));
}

function runAIRecoveryEngine(org_id){
  if (!org_id) return;
  const billedAll = readJSON(FILES.billed, []);
  const ctx = buildClaimContext(org_id);

  for (const claim of billedAll) {
    if (claim.org_id !== org_id) continue;
    const d = evaluateClaimDerived(claim, ctx);

    if (d.lifecycleStage === "Denied") {
      const ws = ensureAgentWorkspace(org_id, claim);
      if (ws.appeal?.auto_generated || shouldLockPacket(ws, "appeal")) continue;
      if (!ws.appeal || !ws.appeal.draft_text) {
        autoDraftWorkspaceForClaim(org_id, claim, d, ctx);
        const wsUpdated = ensureAgentWorkspace(org_id, claim);
        wsUpdated.appeal = wsUpdated.appeal || {};
        wsUpdated.appeal.auto_generated = true;
        wsUpdated.appeal.generated_at = nowISO();
        if (!wsUpdated.appeal.strategy_profile || wsUpdated.appeal.strategy_profile === "Auto") {
          wsUpdated.appeal.strategy_profile = "Regulatory";
        }
        saveAgentWorkspace(org_id, wsUpdated);
        addAgentMessage(org_id, {
          message_id: uuid(),
          workspace_id: wsUpdated.workspace_id,
          billed_id: claim.billed_id,
          role: "agent",
          channel: "appeal",
          content: "AI automatically generated appeal packet based on denial detection.",
          created_at: nowISO()
        });
      }
    }

    if (d.lifecycleStage === "Underpaid") {
      const ws = ensureAgentWorkspace(org_id, claim);
      if (ws.negotiation?.auto_generated || shouldLockPacket(ws, "negotiation")) continue;
      if (!ws.negotiation || !ws.negotiation.draft_text) {
        autoDraftWorkspaceForClaim(org_id, claim, d, ctx);
        const wsUpdated = ensureAgentWorkspace(org_id, claim);
        wsUpdated.negotiation = wsUpdated.negotiation || {};
        wsUpdated.negotiation.auto_generated = true;
        wsUpdated.negotiation.generated_at = nowISO();
        wsUpdated.negotiation.packet_sections = wsUpdated.negotiation.packet_sections || defaultNegotiationPacketSections();
        if (!wsUpdated.negotiation.packet_sections.requested_amount) {
          wsUpdated.negotiation.packet_sections.requested_amount = String(Number(d.underpaidAmount || 0));
        }
        if (!wsUpdated.negotiation.strategy_profile || wsUpdated.negotiation.strategy_profile === "Auto") {
          wsUpdated.negotiation.strategy_profile = "Contractual";
        }
        saveAgentWorkspace(org_id, wsUpdated);
        addAgentMessage(org_id, {
          message_id: uuid(),
          workspace_id: wsUpdated.workspace_id,
          billed_id: claim.billed_id,
          role: "agent",
          channel: "negotiation",
          content: "AI automatically generated negotiation packet based on underpayment detection.",
          created_at: nowISO()
        });
      }
    }
  }
}

function rebuildOrgDerivedData(org_id, opts={}){
  const settings = { resyncDenials: false, autodraft: false, ...opts };
  recalculateContractsForOrg(org_id);
  const billedAll = readJSON(FILES.billed, []);
  const ctx = buildClaimContext(org_id);
  let changed = false;
  for (const b of billedAll) {
    if (b.org_id !== org_id) continue;
    const d = evaluateClaimDerived(b, ctx);
    b.expected_insurance = (d.expectedInsurance == null) ? "" : num(d.expectedInsurance);
    b.underpaid_amount = Math.max(0, num(d.underpaidAmount));
    b.lifecycle_stage = d.lifecycleStage;
    b.status = d.lifecycleStage;
    if (settings.autodraft && ["Denied","Underpaid"].includes(String(d.lifecycleStage || ""))) autoDraftWorkspaceForClaim(org_id, b, d, ctx);
    if (settings.resyncDenials && d.lifecycleStage === "Denied") ensureDenialCaseForClaim(b);
    changed = true;
  }
  if (changed) writeJSON(FILES.billed, billedAll);
  runAIRecoveryEngine(org_id);
  enqueueRecoveryTasksForOrg(org_id);
  runRecoveryAgentTick(org_id);

  const subsAll = readJSON(FILES.billed_submissions, []);
  const orgClaims = billedAll.filter(b => b.org_id === org_id);
  for (const s of subsAll) {
    if (s.org_id !== org_id) continue;
    const claims = orgClaims.filter(c => String(c.submission_id || "") === String(s.submission_id || ""));
    const totals = claims.reduce((acc, c) => {
      const d = evaluateClaimDerived(c, ctx);
      acc.billed += num(c.amount_billed);
      acc.paid += num(d.paidAmount);
      acc.expected += num(d.expectedInsurance);
      return acc;
    }, { billed: 0, paid: 0, expected: 0 });
    s.claim_count = claims.length;
    s.total_billed = totals.billed;
    s.total_paid = totals.paid;
    s.total_expected_insurance = totals.expected;
    s.updated_at = nowISO();
  }
  writeJSON(FILES.billed_submissions, subsAll);
}

function computeClaimAtRisk(b){
  const d = evaluateClaimDerived(b, b?.org_id ? buildClaimContext(b.org_id) : {});
  if (isResolvedLifecycleStage(d.lifecycleStage)) return 0;
  return Math.max(0, d.atRiskAmount);
}

function classifyStatusFromPaymentImport(claim){
  const d = evaluateClaimDerived(claim, {});
  if (d.lifecycleStage === "Waiting Payment") return "Waiting Payment";
  if (d.lifecycleStage === "Submitted") return "Submitted";
  return String(d.lifecycleStage || claim.status || "Pending");
}

function computeClaimRiskScore(b){
  const d = evaluateClaimDerived(b, {});
  const st = String(d.lifecycleStage || b.status || "Pending");
  const atRisk = Math.max(0, d.atRiskAmount);
  const dt = new Date(b.dos || b.denied_at || b.created_at || Date.now()).getTime();
  const days = Math.max(0, (Date.now() - dt) / (1000*60*60*24));
  const amountScore = clamp((Math.log10(atRisk + 1) / 4) * 100, 0, 100); // 40%
  const ageScore = clamp((days / 120) * 100, 0, 100); // 30%
  const stageBase = (st === "Denied") ? 100 : (st === "Underpaid" ? 80 : (st === "In Appeal/Negotiation" ? 70 : (st === "Patient Follow-Up" ? 60 : (st === "Waiting Payment" ? 50 : 30))));
  const networkMod = String(b.network_status || "Out of Network").toLowerCase() === "out of network" ? 100 : 40;
  const total = (0.40 * amountScore) + (0.30 * ageScore) + (0.20 * stageBase) + (0.10 * networkMod);
  return Math.round(clamp(total, 0, 100));
}

function claimRiskBand(score){
  if (score >= 80) return { label: "Critical", cls: "err" };
  if (score >= 60) return { label: "High", cls: "warn" };
  if (score >= 30) return { label: "Moderate", cls: "underpaid" };
  return { label: "Low", cls: "ok" };
}

function suggestedNextActionForClaim(b){
  const st = String(evaluateClaimDerived(b, {}).lifecycleStage || b.status || "Pending");
  if (st === "Denied" || st === "In Appeal/Negotiation") return "Appeal";
  if (st === "Underpaid") return "Negotiate";
  if (st === "Patient Follow-Up") return "Adjust Patient Responsibility";
  return "Review Claim";
}

function formatMoneyUI(v){
  const n = Number(v || 0);
  return n.toLocaleString("en-US", { style: "currency", currency: "USD" });
}

function formatNumberUI(v){
  const n = Number(v || 0);
  return n.toLocaleString("en-US");
}

function clamp01(x){
  x = Number(x || 0);
  return Math.max(0, Math.min(1, x));
}

function formatPct(p){
  const n = Number(p || 0);
  if (!isFinite(n)) return "0%";
  return `${Math.round(n)}%`;
}

function infoIcon(tip){
  return `<span class="tooltip" data-tip="${safeStr(tip)}">ⓘ</span>`;
}

