function computePayerIntelligence(org_id, payerName, preset="last30"){
  if (!payerName) {
    return {
      payerName: "Unknown",
      totalClaims: 0,
      denialRate: 0,
      recoveryRate: 0,
      avgDaysToPay: 0,
      totalUnderpaidDollars: 0,
      totalDeniedDollars: 0,
      totalBilled: 0,
      totalCollected: 0,
      totalAtRisk: 0,
      score: 0,
      grade: gradeFromScore(0),
      denialReasonsTop: [],
      cptTop: [],
      underpaidTrend: Array.from({ length: 8 }, () => 0),
      meta: { preset, resolvedCount: 0, appealCount: 0, followUpCount: 0 }
    };
  }

  const claimsAll = readJSON(FILES.billed, []).filter(b => b.org_id === org_id);
  const ctx = buildClaimContext(org_id);

  const payerKey = canonicalizePayer(payerName);
  const claims = claimsAll.filter(b => canonicalizePayer(b.payer) === payerKey);

  if (!claims.length) {
    return {
      payerName: String(payerName || "").trim() || "Unknown",
      totalClaims: 0,
      denialRate: 0,
      recoveryRate: 0,
      avgDaysToPay: 0,
      totalUnderpaidDollars: 0,
      totalDeniedDollars: 0,
      totalBilled: 0,
      totalCollected: 0,
      totalAtRisk: 0,
      score: 0,
      grade: gradeFromScore(0),
      denialReasonsTop: [],
      cptTop: [],
      underpaidTrend: Array.from({ length: 8 }, () => 0),
      meta: { preset, resolvedCount: 0, appealCount: 0, followUpCount: 0 }
    };
  }

  const now = Date.now();
  const daysToPayVals = [];
  let denialCount = 0;
  let underpaidCount = 0;
  let resolvedCount = 0;
  let appealCount = 0;
  let followUpCount = 0;

  let totalBilled = 0;
  let totalCollected = 0;
  let totalAtRisk = 0;
  let totalDeniedDollars = 0;
  let totalUnderpaidDollars = 0;

  const casesAll = readJSON(FILES.cases, []).filter(c => c.org_id === org_id);
  const casesByBilled = new Map(casesAll.filter(c => c.billed_id).map(c => [String(c.billed_id), c]));

  const denialReasonCounts = {};
  const cptUnderpaidAgg = {};

  for (const b of claims){
    const d = evaluateClaimDerived(b, ctx);
    totalBilled += num(d.billedAmount);
    totalCollected += num(d.paidAmount) + num(b.patient_collected || 0);

    if (!isResolvedLifecycleStage(d.lifecycleStage)) {
      totalAtRisk += Math.max(0, num(d.underpaidAmount)) + Math.max(0, num(d.patientBalanceRemaining));
    }

    const st = String(d.lifecycleStage || "Pending");
    if (st === "Denied"){
      denialCount += 1;
      totalDeniedDollars += Math.max(0, num(d.expectedInsurance || d.billedAmount) - num(d.paidAmount));
      const c = casesByBilled.get(String(b.billed_id || ""));
      const reason = String(c?.ai?.denial_reason_category || c?.denial_reason || c?.issue_reason || b.denial_reason || "").trim() || "Unknown";
      denialReasonCounts[reason] = (denialReasonCounts[reason] || 0) + 1;
    }
    if (st === "Underpaid" || st === "In Appeal/Negotiation"){
      if (st === "Underpaid") underpaidCount += 1;
      if (st === "In Appeal/Negotiation") appealCount += 1;
      totalUnderpaidDollars += Math.max(0, num(d.underpaidAmount));
      const cpt = getClaimProcedureCode(b);
      const label = cpt && cpt !== "UNKNOWN" ? cpt : "";
      if (label) cptUnderpaidAgg[label] = (cptUnderpaidAgg[label] || 0) + Math.max(0, num(d.underpaidAmount));
    }
    if (st === "Resolved" || st === "Write-Off") resolvedCount += 1;
    if (st === "Patient Follow-Up") followUpCount += 1;

    const created = new Date(b.created_at || b.dos || now).getTime();
    if (num(d.paidAmount) > 0 && created && !isNaN(created)){
      const paidAt = new Date(b.paid_at || b.last_paid_at || now).getTime();
      const dt = Math.max(created, 0);
      const dd = Math.max(0, Math.round((paidAt - dt) / (1000*60*60*24)));
      if (isFinite(dd)) daysToPayVals.push(dd);
    }
  }

  const totalClaims = claims.length;
  const denialRate = totalClaims ? (denialCount / totalClaims) * 100 : 0;
  const underpaidRate = totalClaims ? (underpaidCount / totalClaims) * 100 : 0;

  let appealsSubmitted = 0;
  let appealsRecovered = 0;
  for (const b of claims){
    const d = evaluateClaimDerived(b, ctx);
    const c = casesByBilled.get(String(b.billed_id || ""));
    const st = String(c?.status || "").toLowerCase();
    const isAppealSubmitted = st.includes("submitted") || st.includes("approved");
    if (isAppealSubmitted){
      appealsSubmitted += 1;
      if (num(d.paidAmount) > 0) appealsRecovered += 1;
    }
  }
  const recoveryRate = appealsSubmitted ? (appealsRecovered / appealsSubmitted) * 100 : 0;

  const avgDaysToPay = daysToPayVals.length ? (daysToPayVals.reduce((a,b)=>a+b,0)/daysToPayVals.length) : 0;

  const denialScore = 100 - Math.min(100, denialRate);
  const underpaidScore = 100 - Math.min(100, underpaidRate);
  const daysScore = 100 - Math.min(100, (avgDaysToPay / 60) * 100);
  const score = Math.round((0.40 * denialScore) + (0.30 * underpaidScore) + (0.30 * daysScore));
  const grade = gradeFromScore(score);

  const denialReasonsTop = Object.entries(denialReasonCounts)
    .sort((a,b)=>b[1]-a[1])
    .slice(0,5)
    .map(([label,count])=>({ label, count }));

  const cptTop = Object.entries(cptUnderpaidAgg)
    .sort((a,b)=>b[1]-a[1])
    .slice(0,5)
    .map(([label,value])=>({ label, value }));

  const buckets = 8;
  const series = Array.from({ length: buckets }, () => 0);
  for (const b of claims){
    const d = evaluateClaimDerived(b, ctx);
    const dt = new Date(b.created_at || b.dos || now).getTime();
    const ageDays = Math.max(0, Math.round((now - dt)/(1000*60*60*24)));
    const idx = Math.min(buckets - 1, Math.floor((ageDays / Math.max(1, 90)) * buckets));
    series[buckets - 1 - idx] += Math.max(0, num(d.underpaidAmount));
  }

  return {
    payerName: String(payerName || "").trim() || "Unknown",
    totalClaims,
    denialRate,
    recoveryRate,
    avgDaysToPay,
    totalUnderpaidDollars,
    totalDeniedDollars,
    totalBilled,
    totalCollected,
    totalAtRisk,
    score,
    grade,
    denialReasonsTop,
    cptTop,
    underpaidTrend: series,
    meta: { preset, resolvedCount, appealCount, followUpCount }
  };
}

function badgeClassForStatus(st){
  const s = String(st||"Pending");
  if (s === "Paid") return "ok";
  if (s === "Denied") return "err";
  if (s === "Underpaid") return "underpaid";
  if (s === "Appeal") return "warn";
  if (s === "Waiting Payment" || s === "Submitted") return "warn";
  if (s === "Patient Follow-Up" || s === "Follow-Up Needed") return "warn";
  if (s === "Contractual") return "writeoff";
  return "";
}



// ===== Revenue Intelligence Command Center: Saved Queries + Query History =====
function getAIQueries(org_id){
  return readJSON(FILES.ai_queries, []).filter(q => q.org_id === org_id);
}
function saveAIQuery(rec){
  const all = readJSON(FILES.ai_queries, []);
  all.push(rec);
  const perOrg = all.filter(x => x.org_id === rec.org_id);
  if (perOrg.length > 500){
    const sorted = perOrg.sort((a,b)=> new Date(a.created_at||0).getTime() - new Date(b.created_at||0).getTime());
    const toRemove = sorted.slice(0, perOrg.length - 500).map(x=>x.query_id);
    const filtered = all.filter(x => !(x.org_id === rec.org_id && toRemove.includes(x.query_id)));
    writeJSON(FILES.ai_queries, filtered);
  } else {
    writeJSON(FILES.ai_queries, all);
  }
}
function getSavedQueries(org_id){
  return readJSON(FILES.saved_queries, []).filter(q => q.org_id === org_id);
}
function saveSavedQuery(rec){
  const all = readJSON(FILES.saved_queries, []);
  const idx = all.findIndex(x => x.org_id === rec.org_id && x.saved_id === rec.saved_id);
  if (idx >= 0) all[idx] = rec; else all.push(rec);
  writeJSON(FILES.saved_queries, all);
}
function deleteSavedQuery(org_id, saved_id){
  const all = readJSON(FILES.saved_queries, []);
  writeJSON(FILES.saved_queries, all.filter(x => !(x.org_id === org_id && x.saved_id === saved_id)));
}

// ===== Payment Batch Helpers + Soft Delete Log =====
function getDeletedPaymentBatches(org_id){
  return readJSON(FILES.deleted_payment_batches, []).filter(x => x.org_id === org_id);
}
function logDeletedPaymentBatch(rec){
  const all = readJSON(FILES.deleted_payment_batches, []);
  all.push(rec);
  writeJSON(FILES.deleted_payment_batches, all);
}
function normalizeClaimDigits(x){ return String(x || "").replace(/[^0-9]/g, ""); }
function findBilledByClaim(org_id, billedAll, claimNumber){
  const norm = normalizeClaimDigits(claimNumber);
  if (!norm) return null;
  return billedAll.find(b => b.org_id === org_id && normalizeClaimDigits(b.claim_number) === norm) || null;
}
const AI_RESPONSE_STYLES = [
  { key:"exec", label:"Executive Summary + Action Plan" },
  { key:"narrative", label:"Narrative Analysis" },
  { key:"bullets", label:"Bullet Insights" },
  { key:"technical", label:"Technical Breakdown" },
];

function pickChartsForPrompt(prompt){
  const p = String(prompt||"").toLowerCase();
  const charts = new Set();
  charts.add("denial_trend");
  charts.add("payment_trend");
  charts.add("underpay_by_payer");
  if (p.includes("aging") || p.includes("60") || p.includes("90") || p.includes("overdue") || p.includes("at risk")) charts.add("aging_buckets");
  if (p.includes("negotiat")) charts.add("negotiation_success");
  if (p.includes("patient")) charts.add("patient_balance");
  return Array.from(charts);
}

